const form = $input.item.json.form_response || $input.item.json;
const answers = form.answers || [];
const hidden = form.hidden || {};

const get = (ref) => answers.find(a => a.field?.ref === ref);
const getText = (ref) => get(ref)?.text || get(ref)?.choice?.label || hidden[ref] || '';
const getNum = (ref) => parseFloat(get(ref)?.number || get(ref)?.text || 0);

const org = {
  orgName: getText('org_name'),
  orgType: getText('org_type'),
  orgWebsite: getText('org_website'),
  contactName: getText('contact_name'),
  contactEmail: getText('contact_email') || form.hidden?.email || '',
  contactPhone: getText('contact_phone'),
  mission: getText('mission'),
  yearFounded: getText('year_founded'),
  numStaff: getText('num_staff'),
  annualBudget: getText('annual_budget'),
  pastGrants: getText('past_grants'),
  projectTitle: getText('project_title'),
  projectSummary: getText('project_summary'),
  projectLocation: getText('project_location'),
  targetBeneficiaries: getText('target_beneficiaries'),
  projectDuration: getText('project_duration'),
  amountRequested: getNum('amount_requested'),
  totalProjectCost: getNum('total_project_cost'),
  fundingGap: getText('funding_gap'),
  outcomesExpected: getText('outcomes_expected'),
  evaluationPlan: getText('evaluation_plan'),
  grantUrl: getText('grant_url'),
  grantFunder: getText('grant_funder'),
  grantDeadline: getText('grant_deadline'),
  additionalContext: getText('additional_context')
};

if (!org.contactEmail) throw new Error('No contact email provided');
if (!org.grantUrl) throw new Error('No grant URL provided');

org.applicationId = 'GRT-' + Date.now().toString().slice(-7);
org.submittedAt = new Date().toISOString();

return { json: org };

const scraped = $input.item.json.data?.markdown || $input.item.json.markdown || $input.item.json.content || '';
const org = $('Extract Organisation Profile').item.json;

// Truncate scraped content to avoid token overflow
const grantContent = scraped.substring(0, 6000);

return {
  json: {
    ...org,
    grantPageContent: grantContent,
    grantPageLength: scraped.length,
    scrapedAt: new Date().toISOString()
  }
};

const raw = $input.item.json.content?.[0]?.text || '{}';
const org = $('Extract Grant Criteria').item.json;
let assessment;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  assessment = match ? JSON.parse(match[0]) : {};
} catch(e) {
  assessment = { isEligible: true, eligibilityScore: 50, eligibilityReason: 'Could not auto-assess — proceeding to manual review.', keyThemes: [], strengthsForThisGrant: [], weaknesses: ['Eligibility parse error'], keywordsToUse: [], recommendedBudgetApproach: 'Standard approach', winningAngle: 'General impact' };
}
return {
  json: {
    ...org,
    isEligible: assessment.isEligible,
    eligibilityScore: assessment.eligibilityScore || 0,
    eligibilityReason: assessment.eligibilityReason || '',
    keyThemes: assessment.keyThemes || [],
    strengthsForThisGrant: assessment.strengthsForThisGrant || [],
    weaknesses: assessment.weaknesses || [],
    keywordsToUse: assessment.keywordsToUse || [],
    recommendedBudgetApproach: assessment.recommendedBudgetApproach || '',
    winningAngle: assessment.winningAngle || ''
  }
};

const raw = $input.item.json.content?.[0]?.text || '{}';
const org = $('Parse Eligibility Result').item.json;
let proposal;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  proposal = match ? JSON.parse(match[0]) : {};
} catch(e) {
  proposal = { executiveSummary: 'Parse error — regenerate', problemStatement: '', projectDescription: '', methodology: '', expectedOutcomes: '', evaluationPlan: '', organisationalCapacity: '', budgetNarrative: '', sustainability: '', coverLetter: '', titleOptions: [org.projectTitle] };
}
return {
  json: {
    ...org,
    proposal_executiveSummary: proposal.executiveSummary || '',
    proposal_problemStatement: proposal.problemStatement || '',
    proposal_projectDescription: proposal.projectDescription || '',
    proposal_methodology: proposal.methodology || '',
    proposal_expectedOutcomes: proposal.expectedOutcomes || '',
    proposal_evaluationPlan: proposal.evaluationPlan || '',
    proposal_organisationalCapacity: proposal.organisationalCapacity || '',
    proposal_budgetNarrative: proposal.budgetNarrative || '',
    proposal_sustainability: proposal.sustainability || '',
    proposal_coverLetter: proposal.coverLetter || '',
    titleOptions: proposal.titleOptions || [org.projectTitle],
    wordCount: Object.values(proposal).filter(v => typeof v === 'string').join(' ').split(' ').length
  }
};

